const fs = require("fs");
const path = require("path");
const { Project } = require("ts-morph");

// =====================
// CONFIG
// =====================
const UI_DIR = path.resolve(__dirname, "../../../../src/components/shared-ui");
const INDEX_OUTPUT = path.resolve(UI_DIR, "index.ts");

// =====================
// SCAN FILES
// =====================
function getFiles(dir) {
    let result = [];

    const files = fs.readdirSync(dir);

    for (const file of files) {
        const full = path.join(dir, file);
        const stat = fs.statSync(full);

        if (stat.isDirectory()) {
            result = result.concat(getFiles(full));
        } else if (file.endsWith(".tsx") && !file.includes(".test.") && !file.includes(".spec.")) {
            result.push(full);
        }
    }

    return result;
}

// =====================
// MAIN
// =====================
const project = new Project({
    tsConfigFilePath: path.resolve(__dirname, "../../../../tsconfig.json"),
});

const files = getFiles(UI_DIR);

let indexContent =
    `// ⚠️ auto-generated by ts-morph
// updated: ${new Date().toISOString()}

`;

for (const filePath of files) {
    const sourceFile = project.addSourceFileAtPath(filePath);

    const exports = sourceFile.getExportedDeclarations();

    const relative = path
        .relative(UI_DIR, filePath)
        .replace(/\\/g, "/")
        .replace(".tsx", "");

    const importPath = "./" + relative;

    exports.forEach((decls, name) => {
        const first = decls[0];
        if (!first) return;

        const kind = first.getKindName();

        // TYPE exports
        if (
            kind === "InterfaceDeclaration" ||
            kind === "TypeAliasDeclaration"
        ) {
            indexContent += `export type { ${name} } from '${importPath}';\n`;
        } else {
            indexContent += `export { ${name} } from '${importPath}';\n`;
        }
    });
}

// =====================
// WRITE FILE
// =====================
fs.writeFileSync(INDEX_OUTPUT, indexContent);

console.log("🏗️ index.ts generated via ts-morph");
console.log("🎉 DONE");